INSERT INTO `seo_settings` VALUES (1,'/','Ice Van | Refrigeração para Transporte e Isolamento Térmico','Soluções em refrigeração para transporte, isolamento térmico e adaptação de vans, furgões e utilitários. Solicite orçamento rápido com a Ice Van em São Paulo.',NULL,'2026-03-04 15:07:17.156'),(2,'/empresa','Empresa | Especialistas em Refrigeração para Transporte','Conheça a Ice Van, empresa de São Paulo especializada em isolamento térmico, refrigeração veicular e manutenção para vans, furgões e utilitários refrigerados.',NULL,'2026-03-04 15:07:35.575'),(3,'/fotos-servicos','Fotos e Serviços | Portfólio de Refrigeração Veicular','Confira fotos e vídeos dos serviços da Ice Van com instalações de refrigeração veicular, isolamento térmico, acabamento técnico e projetos realizados.',NULL,'2026-03-04 15:07:53.265'),(4,'/contato','Contato | Solicite Orçamento de Refrigeração Veicular','Fale com a Ice Van e solicite orçamento para refrigeração veicular, isolamento térmico, manutenção e adaptação de vans, furgões e utilitários.',NULL,'2026-03-04 15:08:04.406'),(5,'/fiorinos','Refrigeração para Fiorino | Isolamento Térmico Ice Van','Projeto de refrigeração para Fiat Fiorino com isolamento térmico, ideal para transporte de perecíveis, delivery refrigerado e pequenas entregas urbanas.',NULL,'2026-03-04 15:08:16.014'),(6,'/van-ducato','Van Ducato Frigorífica | Refrigeração para Fiat Ducato','Solução de refrigeração para Van Ducato com isolamento térmico, ideal para transporte de alimentos, laticínios, medicamentos e cargas perecíveis.',NULL,'2026-03-04 15:08:24.749'),(7,'/van-sprinter','Van Sprinter Frigorífica | Refrigeração Mercedes Sprinter','Instalação de refrigeração para Mercedes-Benz Sprinter com isolamento térmico e alta capacidade para transporte de alimentos e cargas perecíveis.',NULL,'2026-03-04 15:08:34.680'),(8,'/van-master','Van Master Frigorífica | Refrigeração Renault Master','Refrigeração para Renault Master com isolamento térmico e projeto sob medida para transporte refrigerado, frotas médias e entregas de perecíveis.',NULL,'2026-03-04 15:08:44.061'),(9,'/expert-porta-frigorifica','Expert com Porta Frigorífica | Refrigeração Citroën Peugeot','Adaptação de Citroën e Peugeot Expert com porta frigorífica, isolamento térmico e refrigeração para transporte seguro de alimentos e perecíveis.',NULL,'2026-03-04 15:08:53.149'),(10,'/fiorino-porta-frigorifica','Fiorino com Porta Frigorífica | Refrigeração e Isolamento','Fiat Fiorino com porta frigorífica, isolamento térmico e refrigeração para operações que exigem mais vedação, higiene e controle de temperatura.',NULL,'2026-03-04 15:09:02.016');
