INSERT INTO `settings` VALUES (1,'cor_secundaria','#EB8731'),(2,'cor_primaria','#003957'),(3,'cor_neutra','#F4F6F9'),(4,'cor_destaque','#EB8731'),(5,'cor_texto','#0E0D35'),(6,'cor_destrutivo','#FF5555'),(7,'cor_aviso','#FEB63D'),(8,'cor_fundo','#F4F6F9'),(9,'cor_card','#FFFFFF'),(10,'raio_borda','0.75'),(11,'cor_info','#5B93FF'),(12,'cor_muted','#F8F8F9'),(13,'cor_sucesso','#51CC56'),(14,'empresa_email','vendas@icevans.com.br'),(15,'empresa_horario','Seg a Sex: 8:30h às 17:30h'),(16,'empresa_endereco','Rua paratiji, 18B  penha- Jd. Jáu - São Paulo SP. Cep 03702 000'),(17,'footer_copyright','© 2026 Ice Van. Todos os direitos reservados.'),(18,'empresa_telefone','(11) 91330-8413'),(19,'footer_rodape','CNPJ 54.206.345/0001-25 — Refrigeração para Transporte | São Paulo, SP'),(20,'empresa_descricao','Empresa especializada  em Isolamento térmico e aparelho de refrigeração para vans, Master, Ducato, Sprinter, fiorino, doblo e toda a linha de vans e furgões.'),(21,'hero_filtro_opacidade','35'),(22,'hero_filtro_cor','#2563EB'),(23,'content_solucoes','{\"titulo_secao\":\"Nossas Soluções\",\"subtitulo_secao\":\"Oferecemos dois serviços principais para transformar seu veículo em uma plataforma completa de transporte refrigerado.\",\"cards\":[{\"title\":\"Isolamento Térmico\",\"description\":\"O isolamento térmico é a base para garantir a eficiência da cadeia de frio no transporte de perecíveis. Aplicado em vans, furgões, master, sprinter, ducato, fiorino, doblo e  utilitários, impede a troca de calor entre o interior e o exterior do veículo, mantendo a temperatura estável por mais tempo.\",\"features\":[\"Isolamento térmico em fibra de vidro ante microbiana\",\"Painéis de poliuretano de 50 a 100mm ejetado\",\"Caixas de roda em compensado com acabamento em fibra de vidro ejetado com alumínio reforçado\",\"Piso em fibra de vidro com laminação em manta fio 450 resinado ante infiltração\",\"Acabamento com cantoneiras e aplicação de PU\"]},{\"title\":\"Aparelho de Refrigeração\",\"description\":\"Os aparelhos de refrigeração são instalados em vans, furgões, master, sprinter, ducato, fiorino, doblo e  utilitários e caminhões para manter a temperatura ideal no transporte de cargas perecíveis. Trabalhamos com equipamentos de alta tecnologia, dimensionados conforme o tipo de veículo e a faixa de temperatura exigida.\",\"features\":[\"Compressores originais Sanden Americano\",\"Eletro ventiladores IMOBRAS,  originais\",\"Condensadores embutidos com 02 eletro ventiladores\",\"Evaporado de alta expansão de 30 a 36 tubos\",\"Suporte técnico com revisão e manutenção\"]}]}'),(24,'content_diferenciais','{\"titulo_secao\":\"Por que escolher a\",\"subtitulo_secao\":\"Empresa especializada em Isolamento térmico e aparelho de refrigeração, focada na qualidade,  pontualidade  e a satisfação total de nossos clientes.\",\"cards\":[{\"title\":\"Qualidade Garantida\",\"desc\":\"Materiais de primeira linha e mão de obra especializada com garantia de 12 meses.\"},{\"title\":\"Prazo no Combinado\",\"desc\":\"Cumprimos os prazos de entrega para você não perder tempo nem dinheiro.\"},{\"title\":\"Experiência Comprovada\",\"desc\":\"Anos de atuação no mercado de refrigeração veicular com centenas de instalações realizadas.\"},{\"title\":\"Atendimento Personalizado\",\"desc\":\"Cada projeto é dimensionado conforme o veículo, a carga e a necessidade do cliente.\"}]}'),(25,'content_application_carrao','{\"titulo\":\"CARRÃO\",\"subtitulo\":\"\",\"conteudo\":[\"\"],\"specs\":[{\"label\":\"\",\"valor\":\"\"}]}'),(26,'vehicles_registry','[{\"slug\":\"fiorinos\",\"label\":\"Refrigeração para Fiorinos\",\"href\":\"/fiorinos\",\"ordem\":1},{\"slug\":\"van-ducato\",\"label\":\"Refrigeração em Ducato\",\"href\":\"/van-ducato\",\"ordem\":2},{\"slug\":\"van-sprinter\",\"label\":\"Refrigeração para Sprinter\",\"href\":\"/van-sprinter\",\"ordem\":3},{\"slug\":\"van-master\",\"label\":\"Refrigeração em Master\",\"href\":\"/van-master\",\"ordem\":4},{\"slug\":\"expert-porta-frigorifica\",\"label\":\"Expert com Porta Frigorífica\",\"href\":\"/expert-porta-frigorifica\",\"ordem\":5},{\"slug\":\"fiorino-porta-frigorifica\",\"label\":\"Isolamento Fiorino\",\"href\":\"/fiorino-porta-frigorifica\",\"ordem\":6}]'),(27,'empresa_maps_embed','https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3658.4661227273455!2d-46.54906462391584!3d-23.515731759918935!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x94ce5fad0cf662db%3A0xb8a0a42f95c62a0e!2sRua%20Paratiji%2C%2018B%20-%20Jardim%20Ja%C3%BA%20(Zona%20Leste)%2C%20S%C3%A3o%20Paulo%20-%20SP%2C%2003702-000!5e0!3m2!1spt-BR!2sbr!4v1772232689885!5m2!1spt-BR!2sbr'),(28,'content_application_fiorinos','{\"titulo\":\"Refrigeração para Fiorinos\",\"subtitulo\":\"Isolamento térmico e refrigeração para fiorino, ideal para entregas rápidas.\",\"tituloSecao\":\"Refrigeração Fiorinos\",\"conteudo\":[\"O Fiat Fiorino é um dos veículos utilitários mais utilizados no transporte de perecíveis em centros urbanos. Sua agilidade, baixo consumo e facilidade de estacionamento o tornam a escolha preferida de pequenos empreendedores, padarias, açougues, distribuidoras de laticínios e empresas de delivery refrigerado.\",\"Na Ice Van, desenvolvemos soluções completas de isolamento térmico e refrigeração especialmente dimensionadas para o Fiorino. O processo começa com a aplicação de painéis de poliuretano injetado de alta densidade no baú, garantindo excelente eficiência térmica sem comprometer a capacidade de carga útil do veículo.\",\"Para o sistema de refrigeração, trabalhamos com equipamentos compactos e de alta performance, projetados para manter temperaturas entre -18°C e +8°C, conforme a necessidade do cliente. Os compressores utilizados são de marcas reconhecidas no mercado, garantindo durabilidade e confiabilidade mesmo em operações intensas.\",\"O acabamento interno é realizado em PVC alimentício ou alumínio, materiais de fácil higienização e conformidade com as normas sanitárias da ANVISA para transporte de alimentos. As vedações das portas são reforçadas para garantir a estanqueidade e manutenção da temperatura durante todo o trajeto.\",\"Nossos técnicos realizam a instalação de ponta a ponta — do desmonte do baú original até a entrega do veículo pronto para operação. Todos os trabalhos são executados com garantia e acompanhamento pós-venda, assegurando que o seu Fiorino esteja sempre em plena capacidade de refrigeração.\"],\"specs\":[{\"label\":\"Capacidade de carga\",\"valor\":\"Até 650 kg\"},{\"label\":\"Volume útil do baú\",\"valor\":\"Aprox. 2,5 m³\"},{\"label\":\"Faixa de temperatura\",\"valor\":\"-18°C a +8°C\"},{\"label\":\"Material de isolamento\",\"valor\":\"Poliuretano injetado\"},{\"label\":\"Acabamento interno\",\"valor\":\"PVC alimentício ou alumínio\"},{\"label\":\"Garantia\",\"valor\":\"12 meses (sistema de refrigeração)\"}]}'),(29,'content_cta','{\"titulo\":\"Solicite seu Orçamento\",\"subtitulo\":\"Sem Compromisso\",\"texto\":\"Preencha o formulário ao lado ou entre em contato direto pelo WhatsApp. Nossa equipe responde rapidamente com a solução ideal para o seu veículo.\",\"titulo_form\":\"Fale com nosso time\",\"contatos\":[{\"label\":\"Comercial/Vendas\",\"numero\":\"+55 (11) 91330-8513\"},{\"label\":\"Financeiro\",\"numero\":\"+55 (11) 94824-2999\"},{\"label\":\"Assistência técnica\",\"numero\":\"+55 (11) 96592-3480\"}]}'),(30,'content_application_van-ducato','{\"titulo\":\"Refrigeração em Ducato\",\"subtitulo\":\"Refrigeração em Ducato, uma das vans mais utilizadas no transporte de cargas perecíveis.\",\"tituloSecao\":\"Isolamento e Refrigeração em Van Ducato\",\"conteudo\":[\"O Fiat Ducato é um dos furgões mais populares no Brasil para o transporte refrigerado de médio porte. Com amplo espaço de carga, motor robusto e excelente custo-benefício, o Ducato é a preferência de distribuidoras, redes de supermercados, farmácias e empresas de logística alimentar que precisam de capacidade sem abrir mão da agilidade.\",\"A Ice Van oferece projetos personalizados de isolamento térmico e refrigeração para o Ducato em suas diversas versões (curto, longo, teto elevado). Utilizamos painéis de PU injetado de alta densidade nas paredes, teto e piso, garantindo máxima eficiência térmica e durabilidade estrutural.\",\"Os equipamentos de refrigeração instalados são dimensionados conforme o volume do baú e a faixa de temperatura exigida: desde climatizado (+18°C a +25°C) para produtos sensíveis, até congelados (-18°C) para cargas que exigem temperatura negativa.\",\"Toda a instalação elétrica do sistema de refrigeração é integrada ao circuito elétrico do veículo com proteções adequadas, garantindo segurança e confiabilidade. O painel de controle digital facilita o monitoramento da temperatura em tempo real pelo motorista.\",\"Oferecemos ainda a opção de porta traseira frigorífica com vedação reforçada e sistema de abertura facilitada, ideal para operações de carga e descarga frequentes. Solicite uma visita técnica gratuita para avaliação do seu Ducato e receba um orçamento personalizado.\"],\"specs\":[{\"label\":\"Capacidade de carga\",\"valor\":\"Até 1.500 kg\"},{\"label\":\"Volume útil do baú\",\"valor\":\"8 a 14 m³ (varia por versão)\"},{\"label\":\"Faixa de temperatura\",\"valor\":\"-18°C a +25°C\"},{\"label\":\"Material de isolamento\",\"valor\":\"Poliuretano injetado de alta densidade\"},{\"label\":\"Acabamento interno\",\"valor\":\"Alumínio ou PVC alimentício\"},{\"label\":\"Garantia\",\"valor\":\"12 meses (sistema de refrigeração)\"}]}'),(31,'content_application_van-sprinter','{\"titulo\":\"Refrigeração para Sprinter\",\"subtitulo\":\"Aparelho de refrigeração e isolamento térmico para Sprinter\",\"tituloSecao\":\"Isolamento e Refrigeração para van Sprinter\",\"conteudo\":[\"A Mercedes-Benz Sprinter é referência em furgões de alta capacidade no segmento de transporte refrigerado. Robusta, confiável e com excelente desempenho em rodovias, a Sprinter é amplamente utilizada por distribuidoras de grande porte, redes hospitalares, indústrias alimentícias e operadoras logísticas que exigem máxima performance.\",\"Na Ice Van, desenvolvemos soluções de refrigeração especialmente projetadas para a Sprinter, levando em conta sua estrutura robusta e seu alto volume de carga. O isolamento térmico é executado com painéis de poliuretano de alta densidade (40–60 kg/m³), garantindo baixíssima troca térmica e eficiência energética superior.\",\"Os sistemas de refrigeração instalados são de alta potência, capazes de manter temperaturas estáveis mesmo em condições extremas de calor externo. Trabalhamos com equipamentos de acionamento independente (motor auxiliar diesel ou elétrico), garantindo refrigeração contínua mesmo com o veículo desligado.\",\"O acabamento interno é feito em alumínio ou aço inox, com piso antiderrapante e canais de drenagem para fácil higienização. Todas as instalações seguem as normas sanitárias vigentes para transporte de alimentos e medicamentos.\",\"A Ice Van oferece suporte técnico especializado para a Sprinter, incluindo revisão periódica do sistema de refrigeração, recarga de gás refrigerante e manutenção preventiva. Entre em contato e solicite um projeto personalizado para a sua operação.\"],\"specs\":[{\"label\":\"Capacidade de carga\",\"valor\":\"Até 3.200 kg (varia por versão)\"},{\"label\":\"Volume útil do baú\",\"valor\":\"10 a 17 m³ (varia por versão)\"},{\"label\":\"Faixa de temperatura\",\"valor\":\"-25°C a +25°C\"},{\"label\":\"Material de isolamento\",\"valor\":\"PU injetado 40–60 kg/m³\"},{\"label\":\"Acabamento interno\",\"valor\":\"Alumínio ou aço inox\"},{\"label\":\"Acionamento do sistema\",\"valor\":\"Elétrico ou motor auxiliar diesel\"}]}'),(32,'content_application_van-master','{\"titulo\":\"Refrigeração em Master\",\"subtitulo\":\"Isolamento e refrigeração para Renault Master — excelente custo-benefício para frotas médias.\",\"tituloSecao\":\"Isolamento e Refrigeração em Van Master\",\"conteudo\":[\"A Renault Master é uma excelente opção para frotas médias que buscam volume de carga generoso aliado a custo-benefício competitivo. Muito utilizada por distribuidoras de bebidas, laticínios, produtos farmacêuticos e empresas de alimentação coletiva, a Master oferece versatilidade e robustez para operações urbanas e regionais.\",\"A Ice Van possui ampla experiência na instalação de sistemas de isolamento térmico e refrigeração para a Renault Master em todas as suas versões (curta, longa e teto alto). O processo de adaptação preserva a integridade estrutural do veículo e valoriza o investimento do cliente.\",\"Utilizamos painéis de poliuretano injetado com acabamento em PVC ou alumínio, garantindo eficiência térmica de longa duração. A espessura dos painéis é calculada conforme a faixa de temperatura desejada e as condições climáticas da rota de operação do cliente.\",\"Os sistemas de refrigeração instalados são selecionados conforme a necessidade operacional: resfriados (0°C a +8°C), climatizados (+15°C a +25°C) ou congelados (-18°C a -25°C). Trabalhamos com equipamentos de reconhecida qualidade no mercado nacional e internacional.\",\"Além do serviço de conversão, oferecemos manutenção preventiva e corretiva para sistemas de refrigeração em Van Master, com atendimento rápido e peças de reposição disponíveis. Solicite um orçamento sem compromisso e descubra as melhores soluções para a sua frota.\"],\"specs\":[{\"label\":\"Capacidade de carga\",\"valor\":\"Até 1.300 kg\"},{\"label\":\"Volume útil do baú\",\"valor\":\"8 a 13 m³ (varia por versão)\"},{\"label\":\"Faixa de temperatura\",\"valor\":\"-25°C a +25°C\"},{\"label\":\"Material de isolamento\",\"valor\":\"Poliuretano injetado\"},{\"label\":\"Acabamento interno\",\"valor\":\"PVC ou alumínio\"},{\"label\":\"Garantia\",\"valor\":\"12 meses (sistema de refrigeração)\"}]}'),(33,'content_application_fiorino-porta-frigorifica','{\"titulo\":\"Isolamento Fiorino\",\"subtitulo\":\"Fiat Fiorino com porta frigorífica integrada para operações que exigem mais isolamento.\",\"tituloSecao\":\"Isolamento e refrigeração para fiorino com porta frigorifica para até-18C\",\"conteudo\":[\"O Fiat Fiorino com porta frigorífica é a solução ideal para pequenos negócios que necessitam de um veículo compacto, ágil e com alto grau de isolamento térmico. Perfeito para roteiros urbanos com múltiplas paradas, este equipamento garante que a temperatura interna seja mantida mesmo durante as aberturas frequentes do compartimento de carga.\",\"A versão com porta frigorífica se diferencia da conversão padrão pela instalação de uma porta de alto desempenho com vedação reforçada, juntas magnéticas flexíveis e perfis de alumínio que garantem o mínimo de troca térmica a cada abertura.\",\"O processo de instalação começa com o revestimento interno do baú com painéis de poliuretano injetado de alta densidade (40 kg/m³), seguido pela instalação da porta frigorífica sob medida e do sistema de refrigeração compacto, especialmente selecionado para o volume reduzido do Fiorino.\",\"Apesar do tamanho compacto, o sistema instalado é capaz de manter temperaturas de 0°C a -10°C de forma estável, suficiente para a maioria das aplicações de transporte resfriado urbano. O acabamento interno em PVC alimentício facilita a limpeza e mantém a conformidade sanitária.\",\"A Ice Van oferece um serviço completo de conversão do Fiorino: projeto técnico, instalação e assistência pós-venda. Nosso time de técnicos especializados garante que o seu veículo esteja 100% operacional dentro do prazo acordado. Solicite seu orçamento agora mesmo.\"],\"specs\":[{\"label\":\"Capacidade de carga\",\"valor\":\"Até 600 kg\"},{\"label\":\"Volume útil do baú\",\"valor\":\"Aprox. 2,0 a 2,5 m³\"},{\"label\":\"Faixa de temperatura\",\"valor\":\"0°C a -10°C\"},{\"label\":\"Material de isolamento\",\"valor\":\"PU injetado 40 kg/m³\"},{\"label\":\"Porta frigorífica\",\"valor\":\"Vedação reforçada, junta magnética\"},{\"label\":\"Acabamento interno\",\"valor\":\"PVC alimentício\"}]}'),(34,'empresa_contatos','[{\"label\":\"Comercial/Vendas\",\"numero\":\"+55 (11) 91330-8513\"},{\"label\":\"Financeiro\",\"numero\":\"+55 (11) 94824-2999\"},{\"label\":\"Assistência técnica\",\"numero\":\"+55 (11) 96592-3480\"}]'),(35,'content_empresa','{\"heroLabel\":\"Quem somos\",\"heroTitulo\":\"Empresa especializada em Isolamento térmico e aparelho de refrigeração para toda linha de vans e utilitários.\",\"heroSubtitulo\":\"Oficina especializada em Isolamento térmico,  aparelho de refrigeração e manutenção, para vans, Ducato, Master, Sprinter, Expert, Jumpy, Fiat Scudo, Fiorino, Doblo , Baús e toda a linha de utilitários.\",\"historiaTitle\":\"Nossa História\",\"historiaParagrafos\":[\"A Ice Van nasceu da necessidade de oferecer soluções profissionais de refrigeração para o crescente mercado de transporte de perecíveis no Brasil. Desde o início, nossa proposta foi clara: entregar qualidade técnica, materiais de primeira linha e atendimento consultivo que realmente ajude o cliente a tomar a melhor decisão para o seu negócio.\",\"Ao longo dos anos, instalamos sistemas de refrigeração e isolamento térmico em centenas de veículos — desde Fiorinos para pequenas distribuidoras até Sprinters e Ducatos para grandes frotas. Cada projeto é único e desenvolvido conforme as necessidades específicas de temperatura, volume de carga e perfil de operação do cliente.\",\"Hoje, a Ice Van atua a partir de São Paulo, atendendo clientes de todo o estado com agilidade, seriedade e o mesmo compromisso com a qualidade que sempre nos diferenciou no mercado.\"],\"mvvTitle\":\"Missão, Visão e Valores\",\"mvvSubtitulo\":\"Os pilares que orientam cada projeto e cada relação com nossos clientes.\",\"missao\":{\"titulo\":\"Missão\",\"descricao\":\"Oferecer soluções completas de refrigeração e isolamento térmico para veículos de transporte, garantindo a integridade dos produtos perecíveis e a satisfação total dos nossos clientes.\"},\"visao\":{\"titulo\":\"Visão\",\"descricao\":\"Ser referência nacional no segmento de refrigeração veicular, reconhecidos pela qualidade técnica, inovação e pelo relacionamento de longo prazo com nossos parceiros e clientes.\"},\"valores\":{\"titulo\":\"Valores\",\"descricao\":\"Qualidade sem compromisso. Honestidade nas relações. Comprometimento com o prazo. Respeito ao cliente. Melhoria contínua em processos e materiais.\"},\"diferenciaisTitle\":\"Nossos Diferenciais\",\"diferenciaisLista\":[\"Técnicos especializados e certificados\",\"Materiais de alta qualidade e durabilidade\",\"Projetos personalizados por veículo e aplicação\",\"Cumprimento rigoroso de prazos\",\"Garantia de 12 meses nas instalações\",\"Suporte e assistência técnica pós-venda\",\"Conformidade com normas sanitárias ANVISA\",\"Atendimento consultivo — não somos apenas vendedores\"],\"ctaTitle\":\"Vamos conversar sobre seu projeto?\",\"ctaSubtitulo\":\"Entre em contato agora e descubra como podemos ajudar a transformar seu veículo em uma plataforma de refrigeração profissional.\"}'),(36,'header_telefone','+55 (11) 91330-8513'),(37,'content_application_expert-porta-frigorifica','{\"titulo\":\"Expert com Porta Frigorífica\",\"subtitulo\":\"Citroën/Peugeot Expert adaptado com porta frigorífica de alta vedação.\",\"tituloSecao\":\"Isolamento térmico e Refrigeração para expert com porta frigorifica.\",\"conteudo\":[\"A Citroën Berlingo Expert e a Peugeot Expert são furgões compactos muito utilizados no comércio e na distribuição urbana. Quando equipadas com sistema de isolamento térmico e porta frigorífica de alta vedação, tornam-se plataformas extremamente eficientes para o transporte de alimentos frescos, laticínios, floricultura e produtos farmacêuticos.\",\"A porta frigorífica é um dos elementos mais críticos do sistema de refrigeração. Na Ice Van, instalamos portas com perfis de vedação dupla, juntas magnéticas e dobradiças reforçadas em aço inox, garantindo estanqueidade total e resistência ao uso intensivo.\",\"O processo de conversão da Expert inclui o revestimento completo do compartimento de carga com painéis de poliuretano injetado, seguido pela instalação do sistema de refrigeração e pela montagem da porta frigorífica sob medida. Todo o trabalho é executado sem comprometer a garantia de fábrica do veículo.\",\"Oferecemos acabamento interno em PVC alimentício na cor branca, com perfis de proteção de canto em aço inox para maior durabilidade em operações de carga e descarga. O piso é revestido com material antiderrapante e impermeável, facilitando a higienização.\",\"A combinação de isolamento térmico de qualidade com uma porta frigorífica bem projetada resulta em menor consumo de energia, maior autonomia do sistema de refrigeração e melhor conservação dos produtos. Entre em contato e solicite uma avaliação técnica para a sua Expert.\"],\"specs\":[{\"label\":\"Capacidade de carga\",\"valor\":\"Até 1.000 kg\"},{\"label\":\"Volume útil do baú\",\"valor\":\"Aprox. 5 a 7 m³\"},{\"label\":\"Faixa de temperatura\",\"valor\":\"0°C a +8°C\"},{\"label\":\"Material de isolamento\",\"valor\":\"Poliuretano injetado\"},{\"label\":\"Porta frigorífica\",\"valor\":\"Vedação dupla, junta magnética\"},{\"label\":\"Acabamento interno\",\"valor\":\"PVC alimentício branco\"}]}'),(38,'empresa_nome','Ice Van'),(39,'empresa_slogan','Refrigeração para Transporte com Qualidade e Eficiência'),(40,'empresa_whatsapp','+55 (11) 94824-2999'),(41,'empresa_whatsapp_numero','5511948242999'),(42,'empresa_rua','Rua Gabriela Mistral, 1246'),(43,'empresa_bairro','Penha de França'),(44,'empresa_cidade','São Paulo'),(45,'empresa_estado','SP'),(46,'empresa_cep','03701-000'),(47,'empresa_instagram','https://instagram.com/icevans'),(48,'empresa_facebook',''),(49,'empresa_youtube',''),(50,'empresa_tiktok',''),(51,'empresa_linkedin',''),(52,'empresa_twitter',''),(53,'site_url','https://icevanisolamento.com.br'),(54,'site_og_image','/images/og/og-image.webp'),(55,'site_favicon','/images/logo/favicon.ico'),(56,'google_analytics_id','G-XXXXXXXXXX'),(57,'google_maps_embed','https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3658.9345!2d-46.5484!3d-23.5229!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x0%3A0x0!2sRua+Gabriela+Mistral%2C+1246!5e0!3m2!1spt!2sbr!4v1'),(58,'emailjs_service_id','service_icevans'),(59,'emailjs_template_id','template_contato'),(60,'emailjs_public_key','YOUR_PUBLIC_KEY'),(61,'banner_telefone','+55 (11) 91330-8513');
